import{c as a,Q as i,j as e,m as t}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Скрипт оптимизации базы данных","description":"","frontmatter":{},"headers":[],"relativePath":"ru/scripts/optimize-database.md","filePath":"ru/scripts/optimize-database.md","lastUpdated":1780017229000}'),p={name:"ru/scripts/optimize-database.md"};function l(n,s,d,o,h,c){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="скрипт-оптимизации-базы-данных" tabindex="-1">Скрипт оптимизации базы данных <a class="header-anchor" href="#скрипт-оптимизации-базы-данных" aria-label="Permalink to &quot;Скрипт оптимизации базы данных&quot;">​</a></h1><p>По возможности запускайте этот скрипт в проектном окружении Python:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\optimize_database.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Оптимизирует поддерживаемую проектную базу данных SQLite. Скрипт распознаёт основную библиотечную базу и базу меток Rhythm Lab по маркерным таблицам, создаёт резервную копию, выполняет <code>VACUUM</code>, <code>ANALYZE</code> и проверяет целостность. Он не мигрирует, не восстанавливает и не адаптирует схемы баз данных.</p><p>Используйте этот скрипт после крупного сканирования, сброса, очистки, переноса, анализа, разметки или пересчёта предсказаний, если файл SQLite вырос или вам нужна свежая проверка целостности. Он не входит в обычное повседневное использование и не должен применяться для устранения проблем со схемой или данными.</p><p>Использование:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\optimize_database.py --db DB</span></span></code></pre></div><p>Пример:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\optimize_database.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\optimize_database.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db tools\\rhythm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lab\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\rhythm_lab.sqlite</span></span></code></pre></div><p>Этот скрипт пишет в базу данных и создаёт резервную копию рядом с ней. Если база данных не распознана как основная библиотечная база или база Rhythm Lab, скрипт выводит ошибку и останавливается до создания резервной копии или изменения базы данных.</p><p>Существует только один режим работы и нет dry-run: каждый успешный запуск проверяет базовые маркеры поддержки и целостность, создаёт резервную копию и оптимизирует файл на месте.</p><h2 id="как-это-работает" tabindex="-1">Как это работает <a class="header-anchor" href="#как-это-работает" aria-label="Permalink to &quot;Как это работает&quot;">​</a></h2><ol><li>Требует, чтобы файл <code>--db</code> существовал.</li><li>Выполняет <code>PRAGMA integrity_check</code>; прерывается, если результат не <code>ok</code>.</li><li>Определяет поддерживаемый тип базы по маркерным таблицам: <ul><li>основная библиотека: <code>tracks</code> и <code>embeddings</code></li><li>Rhythm Lab: <code>classifier_profiles</code>, <code>classifier_labels</code>, <code>classifier_predictions</code> и <code>classifier_training_checkpoints</code> Неизвестные SQLite-файлы прерывают работу до создания резервной копии.</li></ul></li><li>Создаёт онлайн-резервную копию SQLite с именем <code>&lt;db-name&gt;.bak-&lt;YYYYMMDD-HHMMSS&gt;</code> рядом с базой данных (если такое имя уже существует, добавляется числовой суффикс).</li><li>Включает журналирование WAL, затем выполняет <code>VACUUM</code>, <code>ANALYZE</code>, <code>PRAGMA optimize</code> и усекающую контрольную точку WAL.</li><li>Снова выполняет <code>PRAGMA integrity_check</code>; прерывается, если результат не <code>ok</code>.</li></ol><h2 id="вывод" tabindex="-1">Вывод <a class="header-anchor" href="#вывод" aria-label="Permalink to &quot;Вывод&quot;">​</a></h2><p>В случае успеха скрипт выводит короткую сводку в стандартный вывод:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>database=&lt;resolved database path&gt;</span></span>
<span class="line"><span>database_kind=&lt;library|rhythm_lab&gt;</span></span>
<span class="line"><span>backup=&lt;backup file path&gt;</span></span>
<span class="line"><span>integrity_before=ok</span></span>
<span class="line"><span>integrity_after=ok</span></span>
<span class="line"><span>size_before=&lt;bytes&gt;</span></span>
<span class="line"><span>size_after=&lt;bytes&gt;</span></span></code></pre></div><p>Единственный файл, который скрипт пишет помимо оптимизированной базы данных, — это резервная копия <code>&lt;db-name&gt;.bak-&lt;timestamp&gt;</code>. Никаких отчётов в формате JSON, XLSX или лога нет.</p><blockquote><p>Внимание: этот скрипт предназначен только для распознанных проектных баз данных. Он отказывается работать с посторонними SQLite-файлами, не мигрирует схемы и не запрашивает подтверждения перед оптимизацией.</p></blockquote><p>Закройте работающее приложение или Rhythm Lab перед оптимизацией той же базы данных, чтобы резервное копирование, <code>VACUUM</code> и проверка целостности выполнялись на спокойном файле.</p>`,19)])])}const b=a(p,[["render",l]]);export{k as __pageData,b as default};
